/// Schedule a scrollend event to be fired after a debounce period
pub(crate) fn schedule_scrollend_event(&self, target: &EventTarget) {
    let target_ptr = target as *const EventTarget as *const u8 as usize;
    let target_id = format!("{:p}", target_ptr);

    // Cancel any existing timer for this target
    if let Some(handle) = self
        .pending_scrollend_timers
        .borrow_mut()
        .remove(&target_id)
    {
        self.window.timers().cancel_timer(handle);
    }

    // Create a new timer for the scrollend event (150ms delay)
    let window = self.window.clone();
    let target_copy = Dom::from_ref(target);
    let timer_callback = OneshotTimerCallback::RunStepsAfterTimeout {
        timer_key: 0,
        ordering_id: DOMString::from("scrollend"),
        milliseconds: 150,
        completion: Box::new(move |_global_scope, _can_gc| {
            // Schedule the scrollend event to be fired
            window
                .Document()
                .fire_scrollend_event_on_target(&target_copy);
        }),
